INSERT INTO approval_requests (id, type, referenceNo, referenceId, title, description, requestedBy, requestedAt, status, approvedBy, approvedAt, reason, amountSen, metadata) VALUES ('apr-001', 'PRICE_OVERRIDE', 'SO-2026-0042', 'so-042', 'Price override for SERA 3-Seater', 'Customer DERA DESIGN requested 8% below list price for bulk order of 20 units SERA 3-Seater sofas.', 'Ahmad Faizal', '2026-04-14T09:15:00+08:00', 'PENDING', NULL, NULL, NULL, 1560000, '{"Original Price":"RM 16,900.00","Requested Price":"RM 15,600.00","Quantity":"20","Customer":"DERA DESIGN SDN BHD"}');
INSERT INTO approval_requests (id, type, referenceNo, referenceId, title, description, requestedBy, requestedAt, status, approvedBy, approvedAt, reason, amountSen, metadata) VALUES ('apr-002', 'DISCOUNT', 'SO-2026-0039', 'so-039', '15% volume discount for ZARA HOME', 'Sales team requests 15% volume discount on mixed order totaling RM 89,400. Exceeds 10% auto-approval threshold.', 'Siti Nurhaliza', '2026-04-14T08:30:00+08:00', 'PENDING', NULL, NULL, NULL, 1341000, '{"Discount %":"15%","Order Total":"RM 89,400.00","Discount Amount":"RM 13,410.00","Customer":"ZARA HOME MY"}');
INSERT INTO approval_requests (id, type, referenceNo, referenceId, title, description, requestedBy, requestedAt, status, approvedBy, approvedAt, reason, amountSen, metadata) VALUES ('apr-003', 'PO_APPROVAL', 'PO-2026-0118', 'po-118', 'Purchase Order - Imported Italian Leather', 'Procurement raised PO for 500 sq ft of premium Italian leather from Milano Pellami. Amount exceeds departmental limit.', 'Lee Wei Ming', '2026-04-13T16:45:00+08:00', 'PENDING', NULL, NULL, NULL, 4250000, '{"Supplier":"Milano Pellami Srl","Material":"Premium Italian Leather","Quantity":"500 sq ft","Lead Time":"45 days"}');
