INSERT INTO approval_requests (id, type, referenceNo, referenceId, title, description, requestedBy, requestedAt, status, approvedBy, approvedAt, reason, amountSen, metadata) VALUES ('apr-005', 'STOCK_ADJUSTMENT', 'SA-2026-0023', 'sa-023', 'Stock write-off - Damaged plywood batch', 'Warehouse reports water damage to 30 sheets of 18mm plywood (Batch PW-2026-B12). Requesting write-off from inventory.', 'Tan Ah Kow', '2026-04-13T11:20:00+08:00', 'PENDING', NULL, NULL, NULL, 720000, '{"Item":"Plywood 18mm","Quantity":"30 sheets","Batch":"PW-2026-B12","Reason":"Water damage","Location":"Warehouse A"}');
