INSERT INTO approval_requests (id, type, referenceNo, referenceId, title, description, requestedBy, requestedAt, status, approvedBy, approvedAt, reason, amountSen, metadata) VALUES ('apr-010', 'PRICE_OVERRIDE', 'SO-2026-0025', 'so-025', 'Price override rejected - Below cost margin', 'Requested price of RM 8,500 for LUXE 2-Seater is below manufacturing cost. Override rejected.', 'Siti Nurhaliza', '2026-04-09T11:00:00+08:00', 'REJECTED', 'Encik Hakimi', '2026-04-09T14:00:00+08:00', 'Requested price is below manufacturing cost of RM 9,200. Minimum acceptable price is RM 10,120 (10% margin).', 850000, '{"Original Price":"RM 12,500.00","Requested Price":"RM 8,500.00","Manufacturing Cost":"RM 9,200.00","Customer":"BUDGET HOMES"}');
