"18MM 4'' X 8'' MR AA PLYWOOD","qty":4,"unit":"PCS","unitCostSen":4500,"totalCostSen":18000,"issuedDate":"2026-02-08","issuedBy":"Ahmad Razif","notes":"For base panel prototype"},{"id":"rdmi-002","rdProjectId":"rd-005","rdProjectCode":"RD-2512-005","materialId":"rm-4","materialCode":"9MM 4'' X 8''","materialName":"9MM 4'' X 8'' MR AA PLYWOOD","qty":2,"unit":"PCS","unitCostSen":3200,"totalCostSen":6400,"issuedDate":"2026-02-08","issuedBy":"Ahmad Razif","notes":"For side panels"}]', '[{"id":"rdlb-001","rdProjectId":"rd-005","workerName":"Ahmad Razif","department":"R&D","hours":8,"date":"2026-02-08","description":"Frame cutting and assembly for v1 prototype"},{"id":"rdlb-002","rdProjectId":"rd-005","workerName":"Tan Mei Ling","department":"R&D","hours":6,"date":"2026-02-09","description":"LED wiring and hydraulic lift installation"},{"id":"rdlb-003","rdProjectId":"rd-005","workerName":"Ahmad Razif","department":"R&D","hours":10,"date":"2026-03-12","description":"v2 prototype reinforcement and LED diffusion improvement"}]', '2025-12-01T09:00:00+08:00', 'ACTIVE');
INSERT INTO rd_prototypes (id, projectId, prototypeType, version, description, materialsCost, labourHours, testResults, feedback, improvements, defects, createdDate) VALUES ('proto-001a', 'rd-001', 'FRAMING', 'v1', 'Initial foam density and frame concept sketch with 3D rendering', 80000, 12, 'Pending', 'Concept looks promising. Need to explore fabric options.', '', 'Frame joints need reinforcement. Foam density too low for long-term durability.', '2026-04-10T09:00:00+08:00');
INSERT INTO rd_prototypes (id, projectId, prototypeType, version, description, materialsCost, labourHours, testResults, feedback, improvements, defects, createdDate) VALUES ('proto-002a', 'rd-002', 'FRAMING', 'v1', 'CAD design of adjustable mechanism with motor placement', 150000, 24, 'Motor torque sufficient for 45-degree adjustment', 'Reduce motor noise. Consider adding soft-close mechanism.', '', 'Motor noise too loud at 55dB. No cable management solution. Missing soft-close.', '2026-03-20T14:00:00+08:00');
INSERT INTO rd_prototypes (id, projectId, prototypeType, version, description, materialsCost, labourHours, testResults, feedback, improvements, defects, createdDate) VALUES ('proto-002b', 'rd-002', 'FRAMING', 'v2', 'Revised design with soft-close damper and cable management', 200000, 18, 'Pending material sourcing for damper', 'Good improvement. Proceed to full-scale prototype after design review.', 'Added soft-close damper. Motor noise reduced to 40dB. Cable management integrated.', 'Damper sourcing uncertain. Cable routing needs refinement for mass production.', '2026-04-08T10:00:00+08:00');
INSERT INTO rd_prototypes (id, projectId, prototypeType, version, description, materialsCost, labourHours, testResults, feedback, improvements, defects, createdDate) VALUES ('proto-003a', 'rd-003', 'FRAMING', 'v1', 'First physical prototype with basic recliner mechanism', 350000, 40, 'Recliner mechanism works but feels stiff. Frame slightly oversized.', 'Reduce frame width by 5cm. Lubricate pivot points.', '', 'Recliner mechanism stiff. Frame 5cm too wide. Pivot points need lubrication.', '2026-03-25T08:00:00+08:00');
INSERT INTO rd_prototypes (id, projectId, prototypeType, version, description, materialsCost, labourHours, testResults, feedback, improvements, defects, createdDate) VALUES ('proto-003b', 'rd-003', 'FRAMING', 'v2', 'Refined prototype with slimmer frame and improved mechanism', 380000, 36, 'Smooth reclining action. Fits within target dimensions.', 'Excellent improvement. Ready for durability testing.', 'Frame width reduced 5cm. Pivot points lubricated. Smooth reclining action.', 'Fabric attachment points not finalized. Need durability testing.', '2026-04-12T09:00:00+08:00');
INSERT INTO rd_prototypes (id, projectId, prototypeType, version, description, materialsCost, labourHours, testResults, feedback, improvements, defects, createdDate) VALUES ('proto-003c', 'rd-003', 'FABRIC_SEWING', 'v3', 'Final prototype with production-grade fabric and foam', 190000, 20, 'In progress - durability and comfort testing', 'Pending test completion', 'Using production-grade fabric. Foam density optimized.', 'Pending durability test results.', '2026-04-14T10:00:00+08:00');
INSERT INTO rd_prototypes (id, projectId, prototypeType, version, description, materialsCost, labourHours, testResults, feedback, improvements, defects, createdDate) VALUES ('proto-004a', 'rd-004', 'FABRIC_SEWING', 'v1', 'Initial sample with outdoor fabric and standard foam', 120000, 8, 'Fabric passed UV test (500hrs). Foam retained water - failed drainage test.', 'Switch to open-cell quick-dry foam. Re-test.', '', 'Foam retained water — failed drainage test. Need open-cell quick-dry foam.', '2026-03-05T11:00:00+08:00');
INSERT INTO rd_prototypes (id, projectId, prototypeType, version, description, materialsCost, labourHours, testResults, feedback, improvements, defects, createdDate) VALUES ('proto-004b', 'rd-004', 'FABRIC_SEWING', 'v2', 'Revised with quick-dry open-cell foam and drainage channels', 180000, 10, 'Water drains in <30 min. UV resistance maintained. In 30-day outdoor exposure test.', 'Looking good. Awaiting full 30-day exposure results.', 'Switched to open-cell quick-dry foam. Added drainage channels.', 'Awaiting 30-day outdoor exposure test results.', '2026-04-01T09:00:00+08:00');
INSERT INTO rd_prototypes (id, projectId, prototypeType, version, description, materialsCost, labourHours, testResults, feedback, improvements, defects, createdDate) VALUES ('proto-005a', 'rd-005', 'FRAMING', 'v1', 'First prototype with basic hydraulic lift mechanism', 450000, 48, 'Lift mechanism works. LED wiring needs improvement.', 'Strengthen base panel. Improve LED diffusion.', '', 'LED wiring exposed. Base panel flex under load. LED diffusion uneven.', '2026-02-10T09:00:00+08:00');
INSERT INTO rd_prototypes (id, projectId, prototypeType, version, description, materialsCost, labourHours, testResults, feedback, improvements, defects, createdDate) VALUES ('proto-005b', 'rd-005', 'FABRIC_SEWING', 'v2', 'Production-ready prototype with improved LED strip and reinforced base', 520000, 40, 'Passed 10,000 cycle lift test. LED colour temp approved. Weight capacity: 250kg verified.', 'Approved for production. Prepare BOM and routing.', 'Base panel reinforced. LED diffusion improved with acrylic strip. Wiring hidden.', '', '2026-03-15T10:00:00+08:00');
